    private static SchemaConstants LoadSchemaConstants()
    {
        const string resourceName = "Extension.Schemas.state-endorsed-digital-identity-credential.json";
        var assembly = typeof(SediCredentialHelper).Assembly;
        using var stream = assembly.GetManifestResourceStream(resourceName)!;
        using var reader = new StreamReader(stream);
        using var doc = JsonDocument.Parse(reader.ReadToEnd());

        var aProps = doc.RootElement
            .GetProperty("properties").GetProperty("a")
            .GetProperty("oneOf")[1].GetProperty("properties");
        var rProps = doc.RootElement
            .GetProperty("properties").GetProperty("r")
            .GetProperty("oneOf")[1].GetProperty("properties");

        var usage = rProps.GetProperty("usageDisclaimer")
            .GetProperty("properties").GetProperty("l").GetProperty("const").GetString()!;
        var privacy = rProps.GetProperty("privacyDisclaimer")
            .GetProperty("properties").GetProperty("l").GetProperty("const").GetString()!;

        var methods = aProps.GetProperty("proofingMethod")
            .GetProperty("oneOf")[1].GetProperty("properties").GetProperty("val").GetProperty("enum")
            .EnumerateArray().Select(e => e.GetString()!).ToArray();
        var levels = aProps.GetProperty("proofingLevel")
            .GetProperty("oneOf")[1].GetProperty("properties").GetProperty("val").GetProperty("enum")
            .EnumerateArray().Select(e => e.GetString()!).ToArray();

        return new SchemaConstants(usage, privacy, methods, levels);
    }
}
